import{_ as e,o as a,c as n,a as i}from"./app.266b6c88.js";var t="/aktivitaeten/schief-gehen-2026-07-22/2.jpg",r="/aktivitaeten/schief-gehen-2026-07-22/3.jpg",h="/aktivitaeten/schief-gehen-2026-07-22/4.jpg",s="/aktivitaeten/schief-gehen-2026-07-22/5.jpg",c="/aktivitaeten/schief-gehen-2026-07-22/6.jpg",m="/aktivitaeten/schief-gehen-2026-07-22/7.jpg",g="/aktivitaeten/schief-gehen-2026-07-22/8.jpg",d="/aktivitaeten/schief-gehen-2026-07-22/9.jpg",l="/aktivitaeten/schief-gehen-2026-07-22/10.jpg",u="/aktivitaeten/schief-gehen-2026-07-22/11.jpg";const o={},p=i('<h1 id="das-war-heute-echt-der-hammer" tabindex="-1"><a class="header-anchor" href="#das-war-heute-echt-der-hammer" aria-hidden="true">#</a> Das war heute echt der Hammer...</h1><h2 id="so-viel-ist-mir-noch-nie-auf-einmal-schiefgegangen" tabindex="-1"><a class="header-anchor" href="#so-viel-ist-mir-noch-nie-auf-einmal-schiefgegangen" aria-hidden="true">#</a> So viel ist mir noch nie auf einmal schiefgegangen.</h2><p>Zuerst bin ich 10 km mit dem Fahrrad zum Bunker geradelt. Oben v\xF6llig platt angekommen, habe ich erst einmal alles aufgebaut.</p><p>Yaesu FT-891 mit 12 V / 12 Ah Akku und SSB auf 15 m. Nach dem zweiten SSB-QSO geht pl\xF6tzlich das Funkger\xE4t aus. Kurzer Check: Akku leer. Den hatte ich nach dem letzten Einsatz wohl vergessen zu laden.</p><p>Zum Gl\xFCck hatte ich noch den FT-818 dabei. Also den internen Akku angeschlossen und mit 2,5 Watt auf FT8 gewechselt. Damit war zwar Betrieb m\xF6glich, aber es war extrem m\xFChsam, die 10 QSOs f\xFCr eine erfolgreiche POTA-Aktivierung (DE-0192 und DE-0919) zusammenzubekommen. Die 25 QSOs f\xFCr den Bunker hatte ich damit von Anfang an abgeschrieben.</p><p>Und nat\xFCrlich: Genau nach dem 10. QSO ging auch der FT-818 aus... Akku ebenfalls leer. War ja klar.</p><p>Dann wollte ich wenigstens noch die Quansheng an die aufgebaute Moxon-Antenne anschlie\xDFen und ein paar QSOs auf 2 m machen. Daf\xFCr hatte ich den FT-818 ja eigentlich dabei \u2013 zumindest FM w\xE4re noch gegangen. Aber heute war wirklich der Wurm drin: Den passenden Adapter hatte ich nat\xFCrlich nicht eingepackt. Also blieb es beim Abbau noch bei einem Relais-QSO und danach ging es wieder mit dem Fahrrad nach Hause. Auf dem R\xFCckweg habe ich mich dann nat\xFCrlich auch noch verfahren, weil ich unbedingt eine neue Strecke ausprobieren wollte. Der Handy-Akku war inzwischen fast leer und der Fahrradakku zeigte auch nur noch einen Balken an. Also hie\xDF es sparsam sein, damit ich den Berg zuhause \xFCberhaupt noch hochkomme. \u{1F605}</p><p><strong>Fazit:</strong><br> Egal, wie lange man das Hobby schon macht \u2013 es passiert immer wieder etwas Neues. Das mit den Akkus passiert mir hoffentlich kein zweites Mal. \u{1F602}</p><p>Positiv hervorzuheben ist aber, dass ich wenigstens an M\xFCckenspray gedacht hatte. So wurde ich zumindest nicht komplett aufgefressen. \u{1F642} Gru\xDF Torsten (DA6TW)</p><p><img src="'+t+'" alt=""><img src="'+r+'" alt=""><img src="'+h+'" alt=""><img src="'+s+'" alt=""><img src="'+c+'" alt=""><img src="'+m+'" alt=""><img src="'+g+'" alt=""><img src="'+d+'" alt=""><img src="'+l+'" alt=""><img src="'+u+'" alt=""></p>',10),k=[p];function f(_,v){return a(),n("div",null,k)}var w=e(o,[["render",f],["__file","2026-07-22-Was-schief-gehen-kann.html.vue"]]);export{w as default};
